using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public static class TestHelpers
{
    public static SchoolContext CreateContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;
        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    public static void DrainNotificationQueue()
    {
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    public static void SeedStudents(SchoolContext context)
    {
        context.Students.AddRange(
            new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { LastName = "Li", FirstMidName = "Yan", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { LastName = "Justice", FirstMidName = "Peggy", EnrollmentDate = new DateTime(2022, 9, 1) }
        );
        context.SaveChanges();
    }

    public static void SeedDepartments(SchoolContext context)
    {
        context.Departments.AddRange(
            new Department { Name = "English", Budget = 100000, StartDate = new DateTime(2020, 1, 1) },
            new Department { Name = "Mathematics", Budget = 200000, StartDate = new DateTime(2020, 1, 1) },
            new Department { Name = "Engineering", Budget = 350000, StartDate = new DateTime(2020, 1, 1) }
        );
        context.SaveChanges();
    }

    public static void SeedCourses(SchoolContext context)
    {
        var dept = context.Departments.FirstOrDefault();
        if (dept == null)
        {
            SeedDepartments(context);
            dept = context.Departments.First();
        }
        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = dept.DepartmentID },
            new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = dept.DepartmentID }
        );
        context.SaveChanges();
    }

    public static void SeedInstructors(SchoolContext context)
    {
        context.Instructors.AddRange(
            new Instructor { LastName = "Abercrombie", FirstMidName = "Kim", HireDate = new DateTime(2020, 3, 11), CourseAssignments = new List<CourseAssignment>() },
            new Instructor { LastName = "Fakhouri", FirstMidName = "Fadi", HireDate = new DateTime(2019, 7, 6), CourseAssignments = new List<CourseAssignment>() },
            new Instructor { LastName = "Harui", FirstMidName = "Roger", HireDate = new DateTime(2018, 7, 1), CourseAssignments = new List<CourseAssignment>() }
        );
        context.SaveChanges();
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public class NotificationServiceTests
{
    private NotificationService _service = null!;

    [TestInitialize]
    public void Setup()
    {
        _service = new NotificationService();
        TestHelpers.DrainNotificationQueue();
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_EnqueuesNotification()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.IsFalse(notification.IsRead);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        _service.SendNotification("Course", "100", "Chemistry", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course", notification.EntityType);
        Assert.AreEqual("100", notification.EntityId);
        Assert.IsTrue(notification.Message.Contains("Chemistry"));
    }

    [TestMethod]
    public void SendNotification_WithUserName_SetsCreatedBy()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Admin", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithNullUserName_DefaultsToSystem()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE, null);

        var notification = _service.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var notification = _service.ReceiveNotification();
        Assert.IsNull(notification);
    }

    [TestMethod]
    public void ReceiveNotification_DequeuesInOrder()
    {
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();

        Assert.IsNotNull(first);
        Assert.IsNotNull(second);
        Assert.AreEqual("A", first.EntityType);
        Assert.AreEqual("B", second.EntityType);
    }

    [TestMethod]
    public void GenerateMessage_Create_WithDisplayName_ContainsCreated()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification()!;
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Update_WithDisplayName_ContainsUpdated()
    {
        _service.SendNotification("Course", "100", "Math", EntityOperation.UPDATE);
        var notification = _service.ReceiveNotification()!;
        Assert.AreEqual("Course 'Math' has been updated", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Delete_WithDisplayName_ContainsDeleted()
    {
        _service.SendNotification("Department", "5", "English", EntityOperation.DELETE);
        var notification = _service.ReceiveNotification()!;
        Assert.AreEqual("Department 'English' has been deleted", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Create_WithoutDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "42", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification()!;
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Update_WithoutDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Course", "100", EntityOperation.UPDATE);
        var notification = _service.ReceiveNotification()!;
        Assert.AreEqual("Course (ID: 100) has been updated", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Delete_WithoutDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Department", "5", EntityOperation.DELETE);
        var notification = _service.ReceiveNotification()!;
        Assert.AreEqual("Department (ID: 5) has been deleted", notification.Message);
    }

    [TestMethod]
    public void QueueCap_EnforcedAt500()
    {
        // Enqueue 510 items
        for (int i = 0; i < 510; i++)
        {
            _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }

        // Count remaining items
        int count = 0;
        while (_service.ReceiveNotification() != null) count++;

        Assert.IsTrue(count <= 500, $"Queue should be capped at 500 but had {count} items");
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        _service.Dispose();
        // Should not throw - just a no-op
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        _service.MarkAsRead(1);
        _service.MarkAsRead(999);
        // No-op, should not throw
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now;
        _service.SendNotification("Test", "1", EntityOperation.CREATE);
        var after = DateTime.Now;

        var notification = _service.ReceiveNotification()!;
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
    }

    [TestMethod]
    public void SendNotification_SetsIsReadToFalse()
    {
        _service.SendNotification("Test", "1", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification()!;
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "1", "", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification()!;
        Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "1", "   ", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification()!;
        Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
    }
}

namespace ContosoUniversity.Tests;

[TestClass]
public class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        var items = new List<string> { "a", "b" };
        var list = new PaginatedList<string>(items, 10, 2, 3);
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
