using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests;

[TestClass]
public class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        TestHelpers.DrainNotificationQueue();
        _context = TestHelpers.CreateContext();
        _controller = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    #region Index

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAsc()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, null, null, null) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count > 0);
        // Default sort is LastName ascending
        for (int i = 0; i < model.Count - 1; i++)
        {
            Assert.IsTrue(string.Compare(model[i].LastName, model[i + 1].LastName, StringComparison.Ordinal) <= 0,
                $"Expected {model[i].LastName} <= {model[i + 1].LastName}");
        }
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDesc()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        for (int i = 0; i < model.Count - 1; i++)
        {
            Assert.IsTrue(string.Compare(model[i].LastName, model[i + 1].LastName, StringComparison.Ordinal) >= 0);
        }
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAsc()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index("Date", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        for (int i = 0; i < model.Count - 1; i++)
        {
            Assert.IsTrue(model[i].EnrollmentDate <= model[i + 1].EnrollmentDate);
        }
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        for (int i = 0; i < model.Count - 1; i++)
        {
            Assert.IsTrue(model[i].EnrollmentDate >= model[i + 1].EnrollmentDate);
        }
    }

    [TestMethod]
    public void Index_SearchString_FiltersResults()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersResults()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, null, "Carson", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Carson", model[0].FirstMidName);
    }

    [TestMethod]
    public void Index_Pagination_ReturnsCorrectPage()
    {
        // Add more than 10 students to test pagination
        for (int i = 0; i < 15; i++)
        {
            _context.Students.Add(new Student
            {
                LastName = $"Student{i:D2}",
                FirstMidName = $"First{i}",
                EnrollmentDate = new DateTime(2020, 1, 1)
            });
        }
        _context.SaveChanges();

        var result1 = _controller.Index(null, null, null, 1) as ViewResult;
        var model1 = result1!.Model as PaginatedList<Student>;
        Assert.AreEqual(10, model1!.Count);
        Assert.IsTrue(model1.HasNextPage);
        Assert.IsFalse(model1.HasPreviousPage);

        var result2 = _controller.Index(null, null, null, 2) as ViewResult;
        var model2 = result2!.Model as PaginatedList<Student>;
        Assert.AreEqual(5, model2!.Count);
        Assert.IsFalse(model2.HasNextPage);
        Assert.IsTrue(model2.HasPreviousPage);
    }

    [TestMethod]
    public void Index_SearchStringResetsPage()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, null, "Li", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        Assert.AreEqual(1, model!.PageIndex);
    }

    [TestMethod]
    public void Index_CurrentFilterUsedWhenSearchStringNull()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, "Li", null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParams()
    {
        TestHelpers.SeedStudents(_context);
        var result = _controller.Index(null, null, null, null) as ViewResult;
        Assert.AreEqual("name_desc", _controller.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _controller.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_DateSort_SetsDateSortParmToDateDesc()
    {
        TestHelpers.SeedStudents(_context);
        _controller.Index("Date", null, null, null);
        Assert.AreEqual("date_desc", _controller.ViewBag.DateSortParm);
    }

    #endregion

    #region Details

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        TestHelpers.SeedStudents(_context);
        var student = _context.Students.First();

        var result = _controller.Details(student.ID) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    [TestMethod]
    public void Details_NotFoundId_ThrowsInvalidOperationException()
    {
        // The controller uses .Single() which throws for no match
        Assert.ThrowsException<InvalidOperationException>(() => _controller.Details(9999));
    }

    #endregion

    #region Create GET

    [TestMethod]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        var result = _controller.Create() as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    #endregion

    #region Create POST

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = new DateTime(2023, 1, 15)
        };

        var result = _controller.Create(student) as RedirectToActionResult;
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(1, _context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_DefaultDate_AddsModelError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = default(DateTime)
        };

        var result = _controller.Create(student) as ViewResult;
        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_MinValueDate_AddsModelError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;
        Assert.IsNotNull(result);
        Assert.IsFalse(_controller.ModelState.IsValid);
    }

    [TestMethod]
    public void Create_Post_ModelError_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "User",
            EnrollmentDate = new DateTime(2023, 1, 15)
        };

        var result = _controller.Create(student) as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_SendsNotification()
    {
        TestHelpers.DrainNotificationQueue();
        var student = new Student
        {
            LastName = "Doe",
            FirstMidName = "John",
            EnrollmentDate = new DateTime(2023, 1, 15)
        };

        _controller.Create(student);

        var svc = new ContosoUniversity.Services.NotificationService();
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.IsTrue(notification.Message.Contains("created"));
    }

    #endregion

    #region Edit GET

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NotFoundId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999) as NotFoundResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        TestHelpers.SeedStudents(_context);
        var student = _context.Students.First();

        var result = _controller.Edit(student.ID) as ViewResult;
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    #endregion

    #region Edit POST

    [TestMethod]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        TestHelpers.SeedStudents(_context);
        var student = _context.Students.First();
        // Detach so we can re-attach with modified state
        _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        student.LastName = "Updated";

        var result = _controller.Edit(student) as RedirectToActionResult;
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_DefaultDate_AddsModelError()
    {
        TestHelpers.SeedStudents(_context);
        var student = _context.Students.First();
        _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        student.EnrollmentDate = default;
        var result = _controller.Edit(student) as ViewResult;
        Assert.IsNotNull(result);
        Assert.IsTrue(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    #endregion

    #region Delete GET

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_Get_NotFoundId_ReturnsNotFound()
    {
        var result = _controller.Delete(9999) as NotFoundResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsView()
    {
        TestHelpers.SeedStudents(_context);
        var student = _context.Students.First();

        var result = _controller.Delete(student.ID) as ViewResult;
        Assert.IsNotNull(result);
        Assert.AreEqual(student.ID, ((Student)result.Model!).ID);
    }

    #endregion

    #region DeleteConfirmed

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesAndRedirects()
    {
        TestHelpers.SeedStudents(_context);
        var student = _context.Students.First();
        int initialCount = _context.Students.Count();

        var result = _controller.DeleteConfirmed(student.ID) as RedirectToActionResult;
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Students.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_SendsDeleteNotification()
    {
        TestHelpers.DrainNotificationQueue();
        TestHelpers.SeedStudents(_context);
        var student = _context.Students.First();

        _controller.DeleteConfirmed(student.ID);

        var svc = new ContosoUniversity.Services.NotificationService();
        var notification = svc.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.IsTrue(notification.Message.Contains("deleted"));
    }

    #endregion
}

