+
+        var svc = new ContosoUniversity.Services.NotificationService();
+        var notification = svc.ReceiveNotification();
+        Assert.IsNotNull(notification);
+        Assert.AreEqual("Course", notification.EntityType);
+        Assert.IsTrue(notification.Message.Contains("Chemistry"));
+    }
+
